 158→const parseLimitWithinRange = (value, min, max, fallback = null) => {
 159→    const parsed = Number.parseInt(value, 10);
 160→    if (Number.isNaN(parsed)) {
 161→        return fallback;
 162→    }
 163→    if (parsed < min || parsed > max) {
 164→        return null;
 165→    }
 166→    return parsed;
 167→};
