 70→        try {
 71→            parsedTags = typeof tags === 'string' ? JSON.parse(tags) : tags;
 72→            if (!Array.isArray(parsedTags)) parsedTags = [];
 73→            parsedTags = parsedTags.slice(0, 10).map(t => String(t).trim()).filter(Boolean);
